import openai

def get_response(user_input):
    system_instructions = ("You are a customer support assistant. "
                           "Answer questions, provide information and help users resolve their issues.")
    
    prompt = f"{system_instructions}\n\nUser: {user_input}\nAI:"
    response = openai.Completion.create(engine='davinci', prompt=prompt, max_tokens=50)
    
    return response['choices'][0]['text'].strip()

while True:
    user_input = input("User: ")
    if user_input == "exit":
        break
    print(f"AI: {get_response(user_input)}")